import{_ as t,a,e as o,f as i,g as r,k as n,i as s,h as l,j as c,l as p,b as d,c as u,d as h}from"./chunks/dev_settings_preview.DVlhR-_b.js";import{d as g,e as m,_ as y,a as f,b,c as w}from"./chunks/data_management.DYhhvOmf.js";import{p as v,bh as k,I as q,U as _}from"./chunks/framework.BpabEsSf.js";const N=JSON.parse('{"title":"Interface Overview","description":"","frontmatter":{"title":"Interface Overview","date":"2026-05-01T23:30:00.000Z","permalink":"/guide/overview","categories":["Introduction"],"tags":["Project"]},"headers":[],"relativePath":"en/01.Guide/01.Introduction/02.Interface Overview.md","filePath":"en/01.Guide/01.Introduction/02.Interface Overview.md","lastUpdated":null}'),P={name:"en/01.Guide/01.Introduction/02.Interface Overview.md"};function T(x,e,S,I,A,M){return k(),q("div",null,[...e[0]||(e[0]=[_('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /en\\01.Guide\\01.Introduction\\02.Interface Overview.md for this page in Markdown format</div><h1 id="interface-overview" tabindex="-1">Interface Overview <a class="header-anchor" href="#interface-overview" aria-label="Permalink to &quot;Interface Overview&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Monica features 7 main screens accessible via the bottom navigation bar: Password Manager, 2FA Authenticator, Card Wallet, Secure Notes, Timeline/Recycle Bin, Password Generator, and Settings.</p><p><img src="'+t+'" alt="Overview" loading="lazy"></p><p>The bottom navigation items can be reordered or toggled on/off based on your personal preference.</p><h2 id="navigation-bar-management" tabindex="-1">Navigation Bar Management <a class="header-anchor" href="#navigation-bar-management" aria-label="Permalink to &quot;Navigation Bar Management&quot;">​</a></h2><p>You can choose to enable only the tabs that are useful to you, keeping your navigation clean and free from clutter.</p><p><img src="'+a+'" alt="Navigation Management" loading="lazy"></p><p>Let&#39;s look at the Password Manager screen first.</p><h2 id="passwords-screen" tabindex="-1">Passwords Screen <a class="header-anchor" href="#passwords-screen" aria-label="Permalink to &quot;Passwords Screen&quot;">​</a></h2><p>From left to right: Passwords main view, expanded stacked item cards, password details, and the edit/add password interface.</p><p>The core interface is straightforward and lets you effortlessly create and manage accounts.</p><p><img src="'+o+'" alt="Passwords Screen" loading="lazy"></p><p>If you configure your &quot;Common Account Info&quot; in Settings, it will automatically populate when creating a new password. You can also tap &quot;Third-Party Login&quot; (shown in figure 2) to reference or link other credentials.</p><p>The top bar of the Passwords screen houses two buttons: the left one opens a bottom drawer to manage your categories; the second controls card stacking behavior (though the default look is already optimized).</p><p><img src="'+i+'" alt="Common Info &amp; Categories" loading="lazy"></p><p>Next is the multi-select screen, triggered by sliding cards to the right.</p><h2 id="multi-select-interface" tabindex="-1">Multi-Select Interface <a class="header-anchor" href="#multi-select-interface" aria-label="Permalink to &quot;Multi-Select Interface&quot;">​</a></h2><p>Swiping right enters the batch action mode, bringing up a bottom utility menu. From left to right, it displays: selected count, select all, add to favorites, add to category, and batch delete.</p><p><img src="'+g+'" alt="Multi-Select Screen" loading="lazy"></p><p>To safeguard against accidental data loss, batch deletion does not bypass user confirmation with biometrics alone. It deliberately forces a protective prompt layout requiring explicit intent to complete.</p><p>As for interaction logic, swiping right directly on a stacked card stack selects the entire group. Tapping a stack expands it instead, allowing for granular single-item selection.</p><p>When not in multi-select mode, a simple left-swipe on an item acts as a delete trigger. This swipe-to-delete logic applies across both Passwords and Authenticator tabs.</p><p>Let&#39;s move on to the 2FA Authenticator screen.</p><h2 id="_2fa-authenticator-screen" tabindex="-1">2FA Authenticator Screen <a class="header-anchor" href="#_2fa-authenticator-screen" aria-label="Permalink to &quot;2FA Authenticator Screen&quot;">​</a></h2><p>The 2FA Authenticator layout is incredibly clean. It follows the same swipe-right to multi-select and swipe-left to delete mechanics.</p><p>Tapping the add button in the bottom right corner opens the full Authenticator configuration page (Figures 2 &amp; 3), where you can manually type parameters or scan QR codes. Alternatively, you can tap the very first icon on the top toolbar (Figure 1) to quickly scan a 2FA QR code on the fly.</p><p><img src="'+r+'" alt="2FA Authenticator Screen" loading="lazy"></p><p>Tapping the three dots on the top right of an authenticator card opens an options menu for quick editing, deletion, or viewing the underlying QR code (perfect for migrating your setups elsewhere).</p><p>Tapping anywhere on a 2FA card copies the token instantly to your clipboard.</p><h2 id="authenticator-extensions" tabindex="-1">Authenticator Extensions <a class="header-anchor" href="#authenticator-extensions" aria-label="Permalink to &quot;Authenticator Extensions&quot;">​</a></h2><p>Under Settings -&gt; Feature Extensions, you can enable &quot;Copy Next Code Near Expiration.&quot; With this on, if you tap the card during the final 5 seconds of a countdown, it will intelligently copy the upcoming code instead of the expiring one.</p><p>You can also toggle &quot;Authenticator Vibration,&quot; which vibrates in tandem with the final 5-second countdown. Turning on the notification display pins selected verification codes inside your Android notification shade for quick lookups (this setting resides in Extensions for now and will be relocated later).</p><p><img src="'+m+'" alt="Feature Extensions Screen" loading="lazy"></p><p>Next up is the Generator tab.</p><h2 id="password-generator" tabindex="-1">Password Generator <a class="header-anchor" href="#password-generator" aria-label="Permalink to &quot;Password Generator&quot;">​</a></h2><p>The Generator page is simple and clean, grouping four distinct types of generators alongside a dedicated history view.</p><p><img src="'+n+'" alt="Generator Screen" loading="lazy"></p><p>The History screen records all your generated configurations, ensuring you never lock yourself out if you create a complex password and forget to hit save.</p><h2 id="secure-notes-screen" tabindex="-1">Secure Notes Screen <a class="header-anchor" href="#secure-notes-screen" aria-label="Permalink to &quot;Secure Notes Screen&quot;">​</a></h2><p>The Secure Notes feature doesn&#39;t aim to replace fully-fledged text editors. It functions beautifully as a secure side-vault for backing up private text information, recovery keys, and seed codes in an encrypted ecosystem.</p><p><img src="'+s+'" alt="Secure Notes Screen" loading="lazy"></p><p>Next is the Card Wallet.</p><h2 id="card-wallet" tabindex="-1">Card Wallet <a class="header-anchor" href="#card-wallet" aria-label="Permalink to &quot;Card Wallet&quot;">​</a></h2><p>The Card Wallet holds financial cards and personal identity credentials. It also supports securely attaching image snapshots of physical IDs, which can be downloaded back to local storage whenever needed.</p><p><img src="'+l+'" alt="Card Wallet Screen" loading="lazy"></p><p>The system keeps it plain and practical. It&#39;s a lifesaver for looking up passport numbers quickly when you don&#39;t have them memorized.</p><p>Let&#39;s look at the History tab.</p><h2 id="history-page" tabindex="-1">History Page <a class="header-anchor" href="#history-page" aria-label="Permalink to &quot;History Page&quot;">​</a></h2><p>The History hub is split into two sections: &quot;Timeline&quot; and &quot;Recycle Bin&quot;.</p><p>The Timeline keeps a chronological audit trail of your changes, allowing you to review past revisions, revert edits on entry fields, or clone historical records into brand new entries. The Recycle Bin lets you instantly recover items you deleted by mistake.</p><p><img src="'+c+'" alt="History Screen" loading="lazy"></p><p>Now, let&#39;s explore Monica&#39;s configuration dashboards.</p><h2 id="aesthetic-theme-engine" tabindex="-1">Aesthetic Theme Engine <a class="header-anchor" href="#aesthetic-theme-engine" aria-label="Permalink to &quot;Aesthetic Theme Engine&quot;">​</a></h2><p>The UI is built entirely on Material 3 (M3) design principles. While it natively samples dynamic accents directly from your system wallpaper, Monica also bundles three distinct preset theme categories:</p><h3 id="category-1-natural-themes" tabindex="-1">Category 1: Natural Themes <a class="header-anchor" href="#category-1-natural-themes" aria-label="Permalink to &quot;Category 1: Natural Themes&quot;">​</a></h3><p>Features 7 color variations: Default, Ocean Blue, Sunset Orange, Forest Green, Tech Purple, Black Mamba, and Soft Black Purple.</p><p><img src="'+y+'" alt="Natural Themes" loading="lazy"></p><p><em>(Fun fact: Black Mamba isn&#39;t entirely deep black, and Soft Black Purple leans towards a muted tone.)</em></p><h3 id="category-2-monet-presets" tabindex="-1">Category 2: Monet Presets <a class="header-anchor" href="#category-2-monet-presets" aria-label="Permalink to &quot;Category 2: Monet Presets&quot;">​</a></h3><p>Features 6 painterly palettes: Water Lilies, Impression Sunrise, The Japanese Bridge, Licorice Team, Rouen Cathedral, and Houses of Parliament - Fog.</p><p><img src="'+f+'" alt="Monet Presets" loading="lazy"></p><p>Among these, Water Lilies is my absolute favorite—it&#39;s incredibly fresh, soft, and easy on the eyes.</p><h3 id="category-3-catppuccin-patches" tabindex="-1">Category 3: Catppuccin Patches <a class="header-anchor" href="#category-3-catppuccin-patches" aria-label="Permalink to &quot;Category 3: Catppuccin Patches&quot;">​</a></h3><p>The famous, beloved Catppuccin color theme ecosystem. If your terminals, Android Studio, and IDE themes use this aesthetic, you will feel right at home.</p><p><img src="'+b+'" alt="Catppuccin Patches" loading="lazy"></p><h2 id="general-appearance-controls" tabindex="-1">General Appearance Controls <a class="header-anchor" href="#general-appearance-controls" aria-label="Permalink to &quot;General Appearance Controls&quot;">​</a></h2><p>The Appearance menu lets you configure your preferred locale language and toggle between light and dark display modes.</p><p><img src="'+p+'" alt="Appearance Settings" loading="lazy"></p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>If &quot;Dynamic Wallpaper Color Sampling&quot; is enabled, chosen preset theme colors will be overridden. Turn off wallpaper sampling to apply your custom presets!</p></div><h2 id="monica-plus" tabindex="-1">Monica Plus <a class="header-anchor" href="#monica-plus" aria-label="Permalink to &quot;Monica Plus&quot;">​</a></h2><p>Monica Plus is an honor-system contribution option; it is <strong>not</strong> a paywall, nor does it gate software features. If you are not in a position to tip, you can tap the unlock button to activate everything for free. Enjoy it without worries!</p><p>Furthermore, enforcing strict server-side licensing checks invites unofficial cracked versions, which often carry unauthorized code adjustments or security backdoors—introducing serious vulnerabilities to users.</p><p>Next are the critical Security parameters.</p><h2 id="security-setup" tabindex="-1">Security Setup <a class="header-anchor" href="#security-setup" aria-label="Permalink to &quot;Security Setup&quot;">​</a></h2><p>Enabling &quot;Fingerprint Unlock&quot; eliminates repetitive master password prompts during standard secure workflows. While face recognition was tested, its high sensitivity triggered unintended authentications during sensitive prompts, so the app relies strictly on secure fingerprint sensors.</p><p>Turning on &quot;Screen Capture Protection&quot; prevents screenshots or screen recordings anywhere inside Monica, keeping your credentials hidden from background malware.</p><p>Here, you can also customize application auto-lock intervals, update your master password, or set security questions. If you forget your master password without setting security questions, your data cannot be recovered, and a complete app data wipe will be required.</p><p>The Security Analyzer checks the health of your saved accounts against vulnerable parameters. This analysis links to the secure, third-party Have I Been Pwned (HIBP) API.</p><p><img src="'+d+'" alt="Security Options" loading="lazy"></p><p>Next is the &quot;Data Management&quot; area.</p><p><img src="'+w+'" alt="Data Management Controls" loading="lazy"></p><p><em>(Yes, the &quot;Extensions&quot; tab accidentally wound up nested here because I rushed out to meet a friend the day I built it! I&#39;ll refactor its location soon.)</em></p><p>This menu handles autofill integration, synchronization workflows, extension toggles, recycle bin clearing, and master resets.</p><p>Let&#39;s look into the Sync and Backup interface.</p><p><img src="'+u+'" alt="Sync &amp; Backup View" loading="lazy"></p><p>When exporting data via Full Backup, tapping the export target a second time opens advanced options to pick and choose specific entry types. This backup matches the underlying structure used in WebDAV automation.</p><p>Exporting formats include standard KeePass structures or Aegis Authenticator schemas, making it easy to transition your data to other software if Monica doesn&#39;t suit your needs.</p><p>WebDAV operations support standard Monica file backups or KeePass-compatible synchronizations. This implementation brings native KeePass file compatibility directly into Monica! Bitwarden-compatible replication is next on our roadmap, as I want this tool to remain incredibly powerful and versatile for everyone.</p><p>Finally, we have the developer utilities.</p><p><img src="'+h+'" alt="Developer Settings &amp; Previews" loading="lazy"></p><p>The Developer Options tab includes an active logging terminal for debugging. <em>(There&#39;s a small bug where real-time logs don&#39;t refresh reliably in the view. Since I debug directly inside Android Studio anyway, I haven&#39;t patched it yet, but it&#39;s on my to-do list.)</em></p><p>You can also toggle off startup password validation completely for rapid testing.</p><p>The Preview section offers experimental features like draggable bottom navigation tracks. While it&#39;s not strictly necessary right now, it serves as a foundation for implementing a swipeable dual-row dock once our feature sets expand. For now, the system is highly stable, so let&#39;s keep it simple!</p><hr>',96)])])}const B=v(P,[["render",T]]);export{N as __pageData,B as default};
